INSERT INTO news (id, source, sourceName, title_en, title_zh, link, timestamp, category, description, tags) VALUES ('axios_9_1774677952', 'axios', 'Axios', 'Mike Johnson faces a rocky path to funding DHS', 'Mike Johnson faces a rocky path to funding DHS', 'https://www.axios.com/2026/03/27/mike-johnson-dhs-funding-freedom-caucus', 1774625711000, '综合', '<p>Hardline House conservatives are threatening to sink a <a href="https://www.axios.com/2026/03/27/dhs-shutdown-senate-vote-trump-tsa-ice-cbp-fema" target="_blank">Senate-passed DHS funding bill</a>, escalating a standoff that''s already kept the agency shut down for more than five weeks.</p><p><str', '["Axios", "\u7efc\u5408"]');
