INSERT INTO news (id, source, sourceName, title_en, title_zh, link, timestamp, category, description, tags) VALUES ('cnn_13_1774677952', 'cnn', 'CNN', 'The surreal facades of America''s strip clubs', 'The surreal facades of America''s strip clubs', 'https://www.cnn.com/style/article/francois-prost-gentlemens-club/index.html', 1678083220000, '综合', 'Some people travel the world in search of adventure, while others seek out natural wonders, cultural landmarks or culinary experiences. But French photographer François Prost was looking for something altogether different during his recent road trip across America: strip clubs.', '["CNN", "\u7efc\u5408"]');
