INSERT INTO news (id, source, sourceName, title_en, title_zh, link, timestamp, category, description, tags) VALUES ('cnn_5_1774677952', 'cnn', 'CNN', 'Not only is Lake Powell''s water level plummeting because of drought, its total capacity is shrinking, too', 'Not only is Lake Powell''s water level plummeting because of drought, its total capacity is shrinking, too', 'https://www.cnn.com/2022/03/21/us/lake-powell-capacity-shrinking-drought-climate/index.html', 1647863664000, '综合', 'Lake Powell, the second-largest human-made reservoir in the US, has lost nearly 7% of its potential storage capacity since 1963, when Glen Canyon Dam was built, a new report shows.', '["CNN", "\u7efc\u5408"]');
